import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  projectId: 'gov-flowise-project',
  apiKey: process.env.VEX_API_KEY,
  policies: ['fedramp-audit', 'nist-80053', 'no-classified-data']
});

// In Flowise chatflow configuration
export const chatflowCallback = async (input: any, output: any) => {
  const result = await vex.verify({
    spanName: 'flowise-chatflow',
    input,
    output,
    metadata: { agency: 'DOD', classification: 'UNCLASSIFIED' }
  });

  if (!result.pass) {
    throw new Error(`Compliance failure: ${result.issues.map(i => i.message).join(', ')}`);
  }
  return output;
};

// Flowise Vector Store Node Callback
const vectorCallback = async (query: string, docs: Document[]) => {
  const vexResult = await vex.verify({
    spanName: 'vector-retrieval',
    input: { query },
    output: { docs: docs.map(d => d.pageContent) },
    policy: 'gov-relevance-threshold',
    threshold: { minRelevance: 0.85 }
  });

  if (vexResult.pass) {
    return docs.filter((doc, i) => vexResult.scores[i] > 0.85);
  }

  console.warn('Low-relevance docs blocked:', vexResult.issues);
  return [];
};

// Agent Handoff Callback
const agentHandoffCallback = async (fromAgent: string, toAgent: string, context: any) => {
  const audit = await vex.verify({
    spanName: `handoff-${fromAgent}-to-${toAgent}`,
    input: context,
    output: context,
    metadata: {
      agents: [fromAgent, toAgent],
      citizenImpact: true,
      appealable: true
    }
  });

  if (!audit.pass) {
    await vex.reportIncident({
      type: 'context-loss',
      severity: 'high',
      regulation: 'EO-AI-explainability'
    });
    throw new Error('Context handoff failed compliance check');
  }

  return { ...context, vexTraceId: audit.traceId };
};
